const body = $("Webhook").first().json.body;
const semanticSearchResult = $("qdrant search memory").first().json.result;
const semanticResults = Array.isArray(semanticSearchResult)
  ? semanticSearchResult
  : semanticSearchResult?.points ?? [];
const profilePoints = $("qdrant scroll profiles").first().json.result?.points ?? [];
const recentReplyContextPoints = $("qdrant scroll recent reply context").first().json.result?.points ?? [];
const staticData = $getWorkflowStaticData("global");
const MAX_SHORT_TERM_AI_TURNS = 6;
const SHORT_TERM_AI_TURN_TTL_MS = 6 * 60 * 60 * 1000;
const shortTermKey = [body.groupId, body.userId].filter(Boolean).join(":");
const aiTurnBuffer = staticData.aiTurnBuffer ?? {};
staticData.aiTurnBuffer = aiTurnBuffer;

const shortTermAiTurns = (
  Array.isArray(aiTurnBuffer[shortTermKey]) ? aiTurnBuffer[shortTermKey] : []
)
  .filter((turn) => Date.now() - Number(turn.savedAt ?? 0) <= SHORT_TERM_AI_TURN_TTL_MS)
  .slice(-MAX_SHORT_TERM_AI_TURNS);

return [
  {
    json: {
      ...body,
      semanticResults,
      profilePoints,
      recentReplyContextPoints,
      shortTermAiTurns,
    },
  },
];

const input = $("prepare memory").first().json;
const chainOutput = $input.first().json;
const aiReply =
  chainOutput.text ??
  chainOutput.output ??
  chainOutput.response ??
  chainOutput.message?.content ??
  chainOutput.choices?.[0]?.message?.content;
const staticData = $getWorkflowStaticData("global");
const MAX_SHORT_TERM_AI_TURNS = 6;
const SHORT_TERM_AI_TURN_TTL_MS = 6 * 60 * 60 * 1000;

if (!aiReply) {
  throw new Error("LLM Chain did not return text/output/response content");
}

function appendAiReplyExportMarker(value) {
  const text = String(value).trimEnd();
  return text.endsWith(".") ? text : text + ".";
}

const markedAiReply = appendAiReplyExportMarker(aiReply);
const shortTermKey = [input.groupId, input.userId].filter(Boolean).join(":");
const aiTurnBuffer = staticData.aiTurnBuffer ?? {};
staticData.aiTurnBuffer = aiTurnBuffer;
const existingTurns = Array.isArray(aiTurnBuffer[shortTermKey])
  ? aiTurnBuffer[shortTermKey]
  : [];
aiTurnBuffer[shortTermKey] = existingTurns
  .filter((turn) => Date.now() - Number(turn.savedAt ?? 0) <= SHORT_TERM_AI_TURN_TTL_MS)
  .concat([
    {
      question: input.text,
      answer: markedAiReply,
      savedAt: Date.now(),
    },
  ])
  .slice(-MAX_SHORT_TERM_AI_TURNS);

return [
  {
    json: {
      to: input.groupId,
      message: markedAiReply,
    },
  },
];

const body = $input.first().json.body ?? $input.first().json;
const image = body.image ?? {};
const mimeType = String(image.mimetype ?? "image/png").split(";")[0].toLowerCase();

function extensionForMimeType(value) {
  if (value === "image/jpeg" || value === "image/jpg") return ".jpg";
  if (value === "image/webp") return ".webp";
  return ".png";
}

function filenameWithExtension(filename, value) {
  const fallback = "input-image" + extensionForMimeType(value);
  const candidate = String(filename ?? fallback).trim();
  const name = candidate ? candidate : fallback;
  return /\.(png|jpe?g|webp)$/i.test(name) ? name : name + extensionForMimeType(value);
}

if (!image.data) {
  throw new Error("Missing image data for image edit");
}

return [
  {
    json: body,
    binary: {
      image: {
        data: image.data,
        mimeType,
        fileName: filenameWithExtension(image.filename, mimeType),
      },
    },
  },
];

const body = $json.body;
const text = String(body.text ?? "").trim();

if (!body.groupId || !body.userId || !body.messageId || text.length < 5) {
  return [];
}

const timestamp = Number(body.timestamp ?? Math.floor(Date.now() / 1000));
const expiresAt = timestamp + 180 * 24 * 60 * 60;

return [
  {
    json: {
      ...body,
      text,
      timestamp,
      expiresAt,
    },
  },
];

