const input = $("parse web search decision").first().json;
const braveOutput = $input.first().json;
const messages = Array.isArray(input.messages) ? [...input.messages] : [];
const STRONG_RESPONSE_MODEL = "deepseek-v4-pro";

function stripHtml(value) {
  return String(value ?? "")
    .replace(/<[^>]*>/g, "")
    .replace(/&quot;/g, '"')
    .replace(/&#x27;/g, "'")
    .replace(/&amp;/g, "&")
    .trim();
}

function normalizeText(value) {
  if (typeof value === "string") return stripHtml(value);
  if (Array.isArray(value)) return value.map(normalizeText).filter(Boolean).join("\n\n");
  if (value && typeof value === "object") {
    return [
      value.title,
      value.description,
      value.snippet,
      value.text,
      value.content,
      value.url ? "Source: " + value.url : ""
    ].map(stripHtml).filter(Boolean).join("\n");
  }
  return "";
}

function firstText(values) {
  for (const value of values) {
    const text = normalizeText(value);
    if (text) return text;
  }
  return "";
}

const llmContext = firstText([
  braveOutput.context,
  braveOutput.full_content,
  braveOutput.llm_context,
  braveOutput.content,
  braveOutput.snippets,
  braveOutput.results
]);

const legacyResults = input.webSearch?.results ?? braveOutput.webSearch?.results ?? [];
const legacyFaq = input.webSearch?.faq ?? braveOutput.webSearch?.faq ?? [];

const faqLines = legacyFaq.map((item, index) =>
  String(index + 1) +
    ". Q: " +
    stripHtml(item.question) +
    "\n   A: " +
    stripHtml(item.answer) +
    "\n   Source: " +
    item.url
);

const resultLines = legacyResults.map((item, index) =>
  String(item.rank ?? index + 1) +
    ". " +
    stripHtml(item.title) +
    (item.age ? " (" + item.age + ")" : "") +
    "\n   Summary: " +
    stripHtml(item.description) +
    (item.extra_snippets?.length ? "\n   Extra: " + item.extra_snippets.map(stripHtml).join(" ") : "") +
    "\n   Source: " +
    item.url
);

const webSearchContext = llmContext
  ? "External web search LLM Context. Use only this extracted content for latest, price, status, news, API, product, or factual web-dependent questions. Add brief sources when useful:\n\n" + llmContext
  : resultLines.length || faqLines.length
    ? "External web search results. Use only these summaries for latest, price, status, news, API, product, or factual web-dependent questions. Do not pretend you opened full pages. Add brief sources when useful:\n\n" +
      [...faqLines, ...resultLines].join("\n\n")
    : input.webSearch?.shouldSearch
      ? "External web search was requested, but no usable search context was returned. Do not invent latest information."
      : "";

if (webSearchContext && messages.length > 0) {
  const lastIndex = messages.length - 1;
  messages[lastIndex] = {
    ...messages[lastIndex],
    content: String(messages[lastIndex].content ?? "") + "\n\n" + webSearchContext
  };
}

return [
  {
    json: {
      ...input,
      webSearch: {
        ...input.webSearch,
        ok: Boolean(webSearchContext),
        provider: "brave_llm_context",
        raw: braveOutput
      },
      messages,
      webSearchContext,
      responseModel: webSearchContext || input.webSearch?.shouldSearch
        ? STRONG_RESPONSE_MODEL
        : input.responseModel
    }
  }
];

const input = $("prepare memory").first().json;
const classifierOutput = $input.first().json;
const raw = classifierOutput.text ?? classifierOutput.output ?? classifierOutput.response ?? classifierOutput.message?.content ?? classifierOutput.choices?.[0]?.message?.content ?? "";

function parseJson(value) {
  const text = String(value || "").trim();
  const fence = String.fromCharCode(96).repeat(3);
  const fenced = text.match(new RegExp(fence + "(?:json)?\\\\s*([\\\\s\\\\S]*?)" + fence, "i"));
  const candidate = fenced ? fenced[1] : text;
  const objectMatch = candidate.match(/\{[\s\S]*\}/);
  if (!objectMatch) throw new Error("classifier returned no json object");
  return JSON.parse(objectMatch[0]);
}

let decision;
try {
  decision = parseJson(raw);
} catch (error) {
  decision = {
    shouldSearch: false,
    query: input.text || "",
    reason: "classifier-unavailable: " + error.message,
  };
}

const query = String(decision.query || input.text || "")
  .replace(/@ai/gi, "")
  .replace(/\s+/g, " ")
  .trim()
  .slice(0, 180);

return [
  {
    json: {
      ...input,
      webSearch: {
        shouldSearch: Boolean(decision.shouldSearch),
        reason: String(decision.reason || ""),
        query,
        classifierRaw: raw,
        results: [],
      },
    },
  },
];

const body = $("Webhook").first().json.body ?? {};
const error = $json.error ?? $json ?? {};

function compact(value) {
  return String(value ?? "")
    .replace(/[\r\n\t]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function safeErrorText(value) {
  const text = compact(value)
    .replace(/sk-[A-Za-z0-9_-]+/g, "[hidden]")
    .replace(/[A-Za-z0-9_-]{32,}/g, "[hidden]");
  return text.slice(0, 220);
}

const candidates = [
  error.message,
  error.description,
  error.cause?.message,
  error.response?.data?.error?.message,
  error.response?.data?.message,
  error.response?.status,
].filter((item) => item !== undefined && item !== null && String(item).trim());

const reason = candidates.length ? safeErrorText(candidates[0]) : "unknown error";

return [
  {
    json: {
      to: body.groupId,
      message: "圖片生成失敗：" + reason + "。可以換張 PNG/JPG 圖、縮短 prompt，或者等服務不忙再試。",
    },
  },
];

