const promptConfig = JSON.parse(fs.readFileSync(PROMPTS_PATH, "utf8"));
const memories = body.retrievedMemories ?? [];
const selectedMemberProfileMemories = body.selectedMemberProfileMemories ?? [];
const memberProfileSelection = body.memberProfileSelection;
const shortTermAiTurns = body.shortTermAiTurns ?? [];
const recentReplyMessages = body.retrievedRecentReplyContext ?? [];
const replyAssistTargetProfile = body.replyAssistTargetProfileRaw ?? null;
const isReplyAssist = body.isReplyAssist;
const responseModel = body.responseModel;
const system = body.system;
const memberProfileContext = body.memberProfileContext;
const memoryContext = body.memoryContext;
const shortTermAiContext = body.shortTermAiContext;
const recentReplyContext = body.recentReplyContext;
const replyAssistInstructions = body.replyAssistInstructions;
return [
  {
    json: {
      ...body,
      retrievedMemories: memories,
      retrievedMemberProfiles: selectedMemberProfileMemories,
      retrievedMemberProfileSelection: memberProfileSelection,
      retrievedShortTermAiTurns: shortTermAiTurns,
      retrievedRecentReplyContext: recentReplyMessages,
      replyAssistTargetProfile: replyAssistTargetProfile ? {
