      responseMode: isReplyAssist ? "reply_assist" : "chat",
      responseModel,
      messages: [
        system,
        {
          role: "user",
          content:
            memberProfileContext +
            "\n\n" +
            memoryContext +
            "\n\n" +
            shortTermAiContext +
            "\n\n" +
            recentReplyContext +
            (replyAssistInstructions ? "\n\n" + replyAssistInstructions : "") +
            promptConfig.strings["assemble_llm_messages_0"] +
            body.text,
        },
      ],
    },
  },
];
